class DeviceIntegrityChecker(private val context: Context) {

    companion object {
        private const val TAG = "DeviceIntegrity"
        private val KNOWN_ROOT_PACKAGES = listOf(
            "com.topjohnwu.magisk",
            "eu.chainfire.supersu",
            "com.koushikdutta.superuser",
            "com.noshufou.android.su",
            "com.thirdparty.superuser",
            "com.yellowes.su"
        )
        private val DANGEROUS_PROPS = listOf(
            "ro.debuggable" to "1",
            "ro.secure" to "0"
        )
        private val SU_PATHS = listOf(
            "/system/app/Superuser.apk",
            "/sbin/su",
            "/system/bin/su",
            "/system/xbin/su",
            "/data/local/xbin/su",
            "/data/local/bin/su",
            "/system/sd/xbin/su",
            "/system/bin/failsafe/su",
            "/data/local/su",
            "/su/bin/su"
        )
    }

    private val rootBeer = RootBeer(context)

    fun performFullIntegrityCheck(): DeviceIntegrityStatus {
        val warnings = mutableListOf<String>()
        val criticalIssues = mutableListOf<String>()

        // Check 1: Root detection via RootBeer library
        if (rootBeer.isRooted) {
            criticalIssues.add("DEVICE_ROOTED")
        }
        if (rootBeer.isRootedWithBusyBoxCheck) {
            criticalIssues.add("BUSYBOX_DETECTED")
        }

        // Check 2: Manual root detection (defense in depth)
        if (checkSuBinaryExists()) {
            criticalIssues.add("SU_BINARY_FOUND")
        }

        // Check 3: Root management apps
        if (checkRootManagementApps()) {
            criticalIssues.add("ROOT_MANAGEMENT_APP_INSTALLED")
        }

        // Check 4: Emulator detection
        if (isEmulator()) {
            warnings.add("EMULATOR_DETECTED")
        }

        // Check 5: Debugger attached
        if (isDebuggerAttached()) {
            criticalIssues.add("DEBUGGER_ATTACHED")
        }

        // Check 6: USB debugging enabled
        if (isUsbDebuggingEnabled()) {
            warnings.add("USB_DEBUGGING_ENABLED")
        }

        // Check 7: App is debuggable
        if (isAppDebuggable()) {
            warnings.add("APP_IS_DEBUGGABLE")
        }

        // Check 8: Installer verification
        if (!isInstalledFromTrustedSource()) {
            warnings.add("UNTRUSTED_INSTALLER")
        }

        // Check 9: Hooking framework detection
        if (isHookingFrameworkDetected()) {
            criticalIssues.add("HOOKING_FRAMEWORK_DETECTED")
        }

        // Check 10: App signature verification
        if (!verifyAppSignature()) {
            criticalIssues.add("APP_SIGNATURE_TAMPERED")
        }

        // Check 11: Test-keys build
        if (isTestKeysBuild()) {
            warnings.add("TEST_KEYS_BUILD")
        }

        return when {
            criticalIssues.isNotEmpty() -> DeviceIntegrityStatus.Untrusted(criticalIssues + warnings)
            warnings.isNotEmpty() -> DeviceIntegrityStatus.Degraded(warnings)
            else -> DeviceIntegrityStatus.Trusted
        }
    }

    private fun checkSuBinaryExists(): Boolean {
        return SU_PATHS.any { path ->
            try {
                File(path).exists()
            } catch (e: Exception) {
                false
            }
        }
    }

    private fun checkRootManagementApps(): Boolean {
        val pm = context.packageManager
        return KNOWN_ROOT_PACKAGES.any { pkg ->
            try {
                pm.getPackageInfo(pkg, 0)
                true
            } catch (e: PackageManager.NameNotFoundException) {
