    private fun isDebuggerAttached(): Boolean {
        return android.os.Debug.isDebuggerConnected() || android.os.Debug.waitingForDebugger()
    }

    private fun isUsbDebuggingEnabled(): Boolean {
        return try {
            Settings.Secure.getInt(
                context.contentResolver,
                Settings.Global.ADB_ENABLED, 0
            ) == 1
        } catch (e: Exception) {
            false
        }
    }

    private fun isAppDebuggable(): Boolean {
        return try {
            (context.applicationInfo.flags and android.content.pm.ApplicationInfo.FLAG_DEBUGGABLE) != 0
        } catch (e: Exception) {
            false
        }
    }

    private fun isInstalledFromTrustedSource(): Boolean {
        val trustedInstallers = listOf(
            "com.android.vending",      // Google Play Store
            "com.amazon.venezia",        // Amazon App Store
            "com.huawei.appmarket",      // Huawei AppGallery
            "com.samsung.android.vending" // Samsung Galaxy Store
        )
        val installer = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            context.packageManager.getInstallSourceInfo(context.packageName).installingPackageName
        } else {
            @Suppress("DEPRECATION")
            context.packageManager.getInstallerPackageName(context.packageName)
        }
        return installer != null && installer in trustedInstallers
    }

    private fun isHookingFrameworkDetected(): Boolean {
        // Check for Xposed
        val xposedDetected = try {
            Class.forName("de.robv.android.xposed.XposedBridge")
            true
        } catch (e: ClassNotFoundException) {
            false
        }

        // Check for Frida
        val fridaDetected = try {
            val fridaPorts = listOf(27042, 27043)
            fridaPorts.any { port ->
                try {
                    java.net.Socket("127.0.0.1", port).use { true }
                } catch (e: Exception) {
                    false
                }
            }
        } catch (e: Exception) {
            false
        }

        // Check for common hooking libraries in loaded native libs
        val hookLibsDetected = try {
            val mapsFile = File("/proc/self/maps")
            if (mapsFile.exists()) {
                val content = mapsFile.readText()
                content.contains("frida") || content.contains("xposed") || content.contains("substrate")
            } else false
        } catch (e: Exception) {
            false
        }

        return xposedDetected || fridaDetected || hookLibsDetected
    }

    private fun verifyAppSignature(): Boolean {
        return try {
            val packageInfo = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                context.packageManager.getPackageInfo(
                    context.packageName,
                    PackageManager.GET_SIGNING_CERTIFICATES
                )
            } else {
                @Suppress("DEPRECATION")
                context.packageManager.getPackageInfo(
                    context.packageName,
                    PackageManager.GET_SIGNATURES
                )
            }

            val signatures = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                packageInfo.signingInfo?.apkContentsSigners
            } else {
                @Suppress("DEPRECATION")
                packageInfo.signatures
            }

            if (signatures.isNullOrEmpty()) return false

            val md = MessageDigest.getInstance("SHA-256")
            val currentHash = Base64.encodeToString(
                md.digest(signatures[0].toByteArray()),
                Base64.NO_WRAP
            )

            // In production, compare against your known release signing certificate hash
            // For now, we just verify a signature exists and is non-empty
            currentHash.isNotEmpty()
        } catch (e: Exception) {
            Log.e(TAG, "Signature verification failed", e)
            false
        }
    }

    private fun isTestKeysBuild(): Boolean {
        return Build.TAGS?.contains("test-keys") == true
    }

    /**
     * Performs Play Integrity API check for server-side verification.
     * Returns the integrity token to be sent to your backend for verification.
     */
    suspend fun requestPlayIntegrityToken(nonce: String): Result<String> {
        return try {
            val integrityManager = IntegrityManagerFactory.create(context)
            val tokenResponse = suspendCancellableCoroutine<Result<String>> { continuation ->
                integrityManager.requestIntegrityToken(
                    IntegrityTokenRequest.builder()
                        .setNonce(nonce)
                        .build()
                ).addOnSuccessListener { response ->
                    continuation.resume(Result.success(response.token()))
                }.addOnFailureListener { exception ->
                    continuation.resume(Result.failure(exception))
                }
            }
            tokenResponse
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Secure Storage using Android Keystore + EncryptedSharedPreferences
// ─────────────────────────────────────────────────────────────────────────────

class SecureStorage(private val context: Context) {

    companion object {
        private const val KEYSTORE_ALIAS = "PaymentModuleKey"
        private const val ENCRYPTED_PREFS_FILE = "secure_payment_prefs"
        private const val KEY_WALLET_BALANCE = "wallet_balance"
        private const val KEY_WALLET_CURRENCY = "wallet_currency"
        private const val KEY_AUTH_TOKEN = "auth_token"
        private const val KEY_SESSION_NONCE = "session_nonce"
        private const val ANDROID_KEYSTORE = "AndroidKeyStore"
        private const val AES_GCM_TRANSFORMATION = "AES/GCM/NoPadding"
        private const val GCM_TAG_LENGTH = 128
        private const val GCM_IV_LENGTH = 12
    }

    private val masterKey: MasterKey by lazy {
        MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .setRequestStrongBoxBacked(true)
            .build()
    }

    private val encryptedPrefs by lazy {
        EncryptedSharedPreferences.create(
            context,
            ENCRYPTED_PREFS_FILE,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    private fun getOrCreateSecretKey(): SecretKey {
        val keyStore = KeyStore.getInstance(ANDROID_KEYSTORE).apply { load(null) }

        if (keyStore.containsAlias(KEYSTORE_ALIAS)) {
            val entry = keyStore.getEntry(KEYSTORE_ALIAS, null) as KeyStore.SecretKeyEntry
            return entry.secretKey
        }

        val keyGenSpec = KeyGenParameterSpec.Builder(
            KEYSTORE_ALIAS,
            KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
        )
            .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
            .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
            .setKeySize(256)
            .setUserAuthenticationRequired(false) // Set true for biometric-gated keys
            .setRandomizedEncryptionRequired(true)
            .apply {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                    setIsStrongBoxBacked(true)
                }
            }
            .build()

        val keyGenerator = KeyGenerator.getInstance(
            KeyProperties.KEY_ALGORITHM_AES,
            ANDROID_KEYSTORE
        )
        keyGenerator.init(keyGenSpec)
        return keyGenerator.generateKey()
    }

    fun encryptData(plaintext: ByteArray): ByteArray {
        val secretKey = getOrCreateSecretKey()
        val cipher = Cipher.getInstance(AES_GCM_TRANSFORMATION)
        cipher.init(Cipher.ENCRYPT_MODE, secretKey)
        val iv = cipher.iv
        val ciphertext = cipher.doFinal(plaintext)
        // Prepend IV to ciphertext
        return iv + ciphertext
    }

    fun decryptData(encryptedData: ByteArray): ByteArray {
        val secretKey = getOrCreateSecretKey()
        val iv = encryptedData.copyOfRange(0, GCM_IV_LENGTH)
        val ciphertext = encryptedData.copyOfRange(GCM_IV_LENGTH, encryptedData.size)
        val cipher = Cipher.getInstance(AES_GCM_TRANSFORMATION)
        val spec = GCMParameterSpec(GCM_TAG_LENGTH, iv)
        cipher.init(Cipher.DECRYPT_MODE, secretKey, spec)
        return cipher.doFinal(ciphertext)
    }

    fun saveWalletBalance(balance: WalletBalance) {
        encryptedPrefs.edit()
            .putString(KEY_WALLET_BALANCE, balance.amount.toString())
            .putString(KEY_WALLET_CURRENCY, balance.currency)
            .apply()
    }

    fun getWalletBalance(): WalletBalance? {
        val amount = encryptedPrefs.getString(KEY_WALLET_BALANCE, null)?.toDoubleOrNull()
            ?: return null
        val currency = encryptedPrefs.getString(KEY_WALLET_CURRENCY, "USD") ?: "USD"
        return WalletBalance(amount, currency)
    }

    fun saveAuthToken(token: String) {
        encryptedPrefs.edit().putString(KEY_AUTH_TOKEN, token).apply()
    }

    fun getAuthToken(): String? {
        return encryptedPrefs.getString(KEY_AUTH_TOKEN, null)
    }

    fun generateAndSaveNonce(): String {
        val nonce = ByteArray(32)
        SecureRandom().nextBytes(nonce)
        val nonceStr = Base64.encodeToString(nonce, Base64.URL_SAFE or Base64.NO_WRAP)
        encryptedPrefs.edit().putString(KEY_SESSION_NONCE, nonceStr).apply()
        return nonceStr
    }

    fun getSessionNonce(): String? {
        return encryptedPrefs.getString(KEY_SESSION_NONCE, null)
    }

    fun clearAll() {
        encryptedPrefs.edit().clear().apply()
    }
}

