// Transaction Logger (Tamper-evident)
// ─────────────────────────────────────────────────────────────────────────────

class TransactionLogger(private val secureStorage: SecureStorage) {

    private val transactions = mutableListOf<TransactionRecord>()
    private var chainHash: String = "GENESIS"

    @Synchronized
    fun logTransaction(transaction: TransactionRecord): String {
        val entryData = "${transaction.transactionId}|${transaction.amount}|" +
                "${transaction.currency}|${transaction.type}|${transaction.status}|" +
                "${transaction.timestamp}|$chainHash"

        val md = MessageDigest.getInstance("SHA-256")
        chainHash = Base64.encodeToString(
            md.digest(entryData.toByteArray(Charsets.UTF_8)),
            Base64.NO_WRAP
        )

        transactions.add(transaction)

        // Encrypt and persist the chain hash
        val encrypted = secureStorage.encryptData(chainHash.toByteArray(Charsets.UTF_8))
        // In production, persist `encrypted` to secure database

        return chainHash
    }

    fun getTransactionHistory(): List<TransactionRecord> = transactions.toList()

    fun verifyChainIntegrity(): Boolean {
        var computedHash = "GENESIS"
        for (tx in transactions) {
            val entryData = "${tx.transactionId}|${tx.amount}|" +
                    "${tx.currency}|${tx.type}|${tx.status}|" +
                    "${tx.timestamp}|$computedHash"
            val md = MessageDigest.getInstance("SHA-256")
            computedHash = Base64.encodeToString(
                md.digest(entryData.toByteArray(Charsets.UTF_8)),
                Base64.NO_WRAP
            )
        }
        return computedHash == chainHash
    }
}

