class PlayBillingManager(
    private val context: Context,
    private val integrityChecker: DeviceIntegrityChecker,
    private val secureStorage: SecureStorage,
    private val transactionLogger: TransactionLogger
) : PurchasesUpdatedListener {

    companion object {
        private const val TAG = "PlayBillingManager"
    }

    private val _purchaseState = MutableStateFlow<PaymentResult?>(null)
    val purchaseState: StateFlow<PaymentResult?> = _purchaseState.asStateFlow()

    private val coroutineScope = CoroutineScope(Dispatchers.Main + SupervisorJob())

    private val billingClient: BillingClient by lazy {
        BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()
    }

    private var isConnected = false

    suspend fun connect(): Boolean {
        return suspendCancellableCoroutine { continuation ->
            billingClient.startConnection(object : BillingClientStateListener {
                override fun onBillingSetupFinished(billingResult: BillingResult) {
                    isConnected = billingResult.responseCode == BillingClient.BillingResponseCode.OK
                    if (continuation.isActive) {
                        continuation.resume(isConnected)
                    }
                }

                override fun onBillingServiceDisconnected() {
                    isConnected = false
                }
            })
        }
    }

    override fun onPurchasesUpdated(
        billingResult: BillingResult,
        purchases: MutableList<Purchase>?
    ) {
        when (billingResult.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                purchases?.forEach { purchase ->
                    coroutineScope.launch {
                        handlePurchase(purchase)
                    }
                }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> {
                _purchaseState.value = PaymentResult.Failure(
                    billingResult.responseCode,
                    "Purchase cancelled by user"
                )
            }
            else -> {
                _purchaseState.value = PaymentResult.Failure(
                    billingResult.responseCode,
                    billingResult.debugMessage
                )
            }
        }
    }

    private suspend fun handlePurchase(purchase: Purchase) {
        // Step 1: Verify device integrity before acknowledging purchase
        val integrityStatus = integrityChecker.performFullIntegrityCheck()
        val integrityVerified: Boolean

        when (integrityStatus) {
            is DeviceIntegrityStatus.Untrusted -> {
                Log.e(TAG, "Device integrity check FAILED: ${integrityStatus.reasons}")
                _purchaseState.value = PaymentResult.IntegrityFailure(
                    "Device integrity verification failed. Purchase cannot be processed on this device."
                )
                // Do NOT acknowledge the purchase — it will be refunded automatically
                return
            }
            is DeviceIntegrityStatus.Degraded -> {
                Log.w(TAG, "Device integrity degraded: ${integrityStatus.warnings}")
                // Allow but flag for additional server-side verification
                integrityVerified = false
            }
            is DeviceIntegrityStatus.Trusted -> {
                integrityVerified = true
            }
        }

        // Step 2: Request Play Integrity token for server-side verification
        val nonce = secureStorage.generateAndSaveNonce()
        val integrityTokenResult = integrityChecker.requestPlayIntegrityToken(nonce)

        if (integrityTokenResult.isFailure) {
            Log.w(TAG, "Play Integrity token request failed, proceeding with local checks only")
        }

        // Step 3: Verify purchase signature (Google Play handles this, but we double-check)
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            if (!purchase.isAcknowledged) {
                // Step 4: Send to backend for server-side verification
                // In production: send purchase.purchaseToken + integrityToken to your server
                val serverVerified = verifyPurchaseOnServer(
                    purchase,
                    integrityTokenResult.getOrNull()
                )

                if (!serverVerified) {
                    _purchaseState.value = PaymentResult.Failure(
                        -1,
                        "Server-side purchase verification failed"
                    )
                    return
                }

                // Step 5: Acknowledge the purchase
                val acknowledgePurchaseParams = AcknowledgePurchaseParams.newBuilder()
                    .setPurchaseToken(purchase.purchaseToken)
                    .build()

                val ackResult = withContext(Dispatchers.IO) {
                    suspendCancellableCoroutine<BillingResult> { continuation ->
                        billingClient.acknowledgePurchase(acknowledgePurchaseParams) { result ->
                            continuation.resume(result)
                        }
                    }
                }

                if (ackResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    val transaction = TransactionRecord(
                        transactionId = purchase.orderId ?: generateTransactionId(),
                        amount = 0.0, // Resolved from product details
                        currency = "USD",
                        type = TransactionType.PURCHASE,
                        status = TransactionStatus.COMPLETED,
                        timestamp = purchase.purchaseTime,
                        description = purchase.products.joinToString(", "),
                        integrityVerified = integrityVerified
                    )
                    transactionLogger.logTransaction(transaction)
                    _purchaseState.value = PaymentResult.Success(transaction)
                } else {
                    _purchaseState.value = PaymentResult.Failure(
                        ackResult.responseCode,
                        "Failed to acknowledge purchase"
                    )
                }
            }
        }
    }

    private suspend fun verifyPurchaseOnServer(
        purchase: Purchase,
        integrityToken: String?
    ): Boolean {
        // In production, make an HTTPS call to your backend:
        // POST /api/verify-purchase
        // Body: { purchaseToken, orderId, productId, integrityToken, nonce }
        // The server should:
        // 1. Verify the purchase with Google Play Developer API
        // 2. Decode and verify the integrity token with Play Integrity API
        // 3. Check the nonce matches
        // 4. Return verification result

        // Placeholder — always returns true for demo
        // IMPORTANT: Replace with actual server call in production
        return withContext(Dispatchers.IO) {
            // Simulate network call
            delay(100)
            true
        }
    }

    suspend fun queryProducts(productIds: List<String>): List<ProductDetails> {
        if (!isConnected) connect()

        val productList = productIds.map { productId ->
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(BillingClient.ProductType.INAPP)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        return suspendCancellableCoroutine { continuation ->
            billingClient.queryProductDetailsAsync(params) { billingResult, productDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    continuation.resume(productDetailsList)
                } else {
                    continuation.resume(emptyList())
                }
            }
        }
    }

    fun disconnect() {
        if (billingClient.isReady) {
            billingClient.endConnection()
        }
        coroutineScope.cancel()
    }

    private fun generateTransactionId(): String {
        val bytes = ByteArray(16)
        SecureRandom().nextBytes(bytes)
        return "TXN-${Base64.encodeToString(bytes, Base64.URL_SAFE or Base64.NO_WRAP)}"
    }
}

