) {

    companion object {
        private const val TAG = "WalletManager"
        private const val MAX_TRANSACTION_AMOUNT = 10000.0
        private const val MIN_TRANSACTION_AMOUNT = 0.01
        private const val RATE_LIMIT_WINDOW_MS = 60_000L // 1 minute
        private const val MAX_TRANSACTIONS_PER_WINDOW = 10
    }

    private val _walletState = MutableStateFlow<WalletBalance?>(null)
    val walletState: StateFlow<WalletBalance?> = _walletState.asStateFlow()

    private val recentTransactionTimestamps = mutableListOf<Long>()

    init {
        _walletState.value = secureStorage.getWalletBalance()
    }

    suspend fun processWalletTransaction(
        amount: Double,
        type: TransactionType,
        description: String
    ): PaymentResult {
        // Step 1: Device integrity check
        val integrityStatus = integrityChecker.performFullIntegrityCheck()
        when (integrityStatus) {
            is DeviceIntegrityStatus.Untrusted -> {
                Log.e(TAG, "Wallet transaction blocked: device untrusted - ${integrityStatus.reasons}")
                return PaymentResult.IntegrityFailure(
                    "Transaction blocked: Device integrity verification failed. " +
                            "Reasons: ${integrityStatus.reasons.joinToString(", ")}"
                )
            }
            is DeviceIntegrityStatus.Degraded -> {
                Log.w(TAG, "Wallet transaction on degraded device: ${integrityStatus.warnings}")
                // For high-value transactions on degraded devices, require additional verification
                if (amount > 100.0) {
                    return PaymentResult.IntegrityFailure(
                        "High-value transactions require a fully verified device. " +
                                "Issues detected: ${integrityStatus.warnings.joinToString(", ")}"
                    )
                }
            }
            is DeviceIntegrityStatus.Trusted -> {
                // Proceed normally
            }
        }

        // Step 2: Input validation
        if (amount < MIN_TRANSACTION_AMOUNT || amount > MAX_TRANSACTION_AMOUNT) {
            return PaymentResult.Failure(
                -2,
                "Invalid amount. Must be between $MIN_TRANSACTION_AMOUNT and $MAX_TRANSACTION_AMOUNT"
            )
        }

        // Step 3: Rate limiting
        if (!checkRateLimit()) {
            return PaymentResult.Failure(
                -3,
                "Too many transactions. Please wait before trying again."
            )
        }

        // Step 4: Verify transaction log integrity before proceeding
        if (!transactionLogger.verifyChainIntegrity()) {
            Log.e(TAG, "Transaction log integrity check failed!")
            return PaymentResult.IntegrityFailure(
                "Transaction log integrity verification failed. Possible tampering detected."
            )
        }

        // Step 5: Play Integrity API verification for server-side validation
        val nonce = secureStorage.generateAndSaveNonce()
        val integrityToken = integrityChecker.requestPlayIntegrityToken(nonce)

        // Step 6: Process the transaction
        return try {
            val currentBalance = secureStorage.getWalletBalance()
                ?: WalletBalance(0.0, "USD")

            val newBalance = when (type) {
                TransactionType.WALLET_TOP_UP -> {
                    currentBalance.copy(
                        amount = currentBalance.amount + amount,
                        lastUpdated = System.currentTimeMillis()
                    )
                }
                TransactionType.WALLET_WITHDRAWAL, TransactionType.PURCHASE -> {
                    if (currentBalance.amount < amount) {
                        return PaymentResult.Failure(-4, "Insufficient balance")
                    }
                    currentBalance.copy(
                        amount = currentBalance.amount - amount,
                        lastUpdated = System.currentTimeMillis()
                    )
                }
                TransactionType.REFUND -> {
                    currentBalance.copy(
                        amount = currentBalance.amount + amount,
                        lastUpdated = System.currentTimeMillis()
                    )
                }
                else -> return PaymentResult.Failure(-5, "Unsupported transaction type for wallet")
            }

            // Step 7: Server-side verification (in production)
            val serverApproved = verifyTransactionOnServer(
                amount = amount,
                type = type,
                integrityToken = integrityToken.getOrNull(),
                nonce = nonce
            )

            if (!serverApproved) {
                return PaymentResult.Failure(-6, "Server rejected the transaction")
            }

            // Step 8: Persist new balance
            secureStorage.saveWalletBalance(newBalance)
            _walletState.value = newBalance

            // Step 9: Log the transaction
            val transaction = TransactionRecord(
                transactionId = generateTransactionId(),
                amount = amount,
                currency = newBalance.currency,
                type = type,
                status = TransactionStatus.COMPLETED,
                timestamp = System.currentTimeMillis(),
                description = description,
                integrityVerified = integrityStatus is DeviceIntegrityStatus.Trusted
            )
            transactionLogger.logTransaction(transaction)

            recordTransactionTimestamp()

            PaymentResult.Success(transaction)
        } catch (e: Exception) {
            Log.e(TAG, "Wallet transaction failed", e)
            PaymentResult.Failure(-99, "Transaction failed: ${e.message}")
        }
    }

    private suspend fun verifyTransactionOnServer(
        amount: Double,
        type: TransactionType,
        integrityToken: String?,
        nonce: String
    ): Boolean {
        // In production, make HTTPS call to your backend:
        // POST /api/verify-wallet-transaction
        // Body: { amount, type, integrityToken, nonce, authToken }
        // Server should:
        // 1. Verify the integrity token
        // 2. Validate the nonce
        // 3. Check user's server-side balance
        // 4. Apply transaction atomically
        // 5. Return result

        return withContext(Dispatchers.IO) {
            delay(50) // Simulate network
            true
        }
    }

    @Synchronized
    private fun checkRateLimit(): Boolean {
        val now = System.currentTimeMillis()
        recentTransactionTimestamps.removeAll { now - it > RATE_LIMIT_WINDOW_MS }
        return recentTransactionTimestamps.size < MAX_TRANSACTIONS_PER_WINDOW
    }

    @Synchronized
    private fun recordTransactionTimestamp() {
        recentTransactionTimestamps.add(System.currentTimeMillis())
    }

    fun getBalance(): WalletBalance? = secureStorage.getWalletBalance()

    fun getTransactionHistory(): List<TransactionRecord> = transactionLogger.getTransactionHistory()

    private fun generateTransactionId(): String {
        val bytes = ByteArray(16)
        SecureRandom().nextBytes(bytes)
        return "WLT-${System.currentTimeMillis()}-${
            Base64.encodeToString(bytes, Base64.URL_SAFE or Base64.NO_WRAP)
        }"
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Payment Module Facade
// ─────────────────────────────────────────────────────────────────────────────

class PaymentModule private constructor(
    private val context: Context
) {
    companion object {
        private const val TAG = "PaymentModule"

        @Volatile
        private var instance: PaymentModule? = null

        fun getInstance(context: Context): PaymentModule {
            return instance ?: synchronized(this) {
                instance ?: PaymentModule(context.applicationContext).also {
                    instance = it
                }
            }
        }
    }

    val integrityChecker = DeviceIntegrityChecker(context)
    val secureStorage = SecureStorage(context)
    private val transactionLogger = TransactionLogger(secureStorage)

    val billingManager = PlayBillingManager(
        context, integrityChecker, secureStorage, transactionLogger
    )

    val walletManager = WalletManager(
        context, secureStorage, integrityChecker, transactionLogger
    )

    private var initialized = false

    /**
     * Initialize the payment module. Must be called before any operations.
     * Performs initial device integrity check.
     */
    suspend fun initialize(): Result<DeviceIntegrityStatus> {
        return try {
            // Perform initial integrity check
            val integrityStatus = integrityChecker.performFullIntegrityCheck()

            when (integrityStatus) {
                is DeviceIntegrityStatus.Untrusted -> {
                    Log.e(TAG, "Payment module initialization blocked: ${integrityStatus.reasons}")
                    // Still initialize but in restricted mode
                }
                is DeviceIntegrityStatus.Degraded -> {
                    Log.w(TAG, "Payment module initialized with warnings: ${integrityStatus.warnings}")
                }
                is DeviceIntegrityStatus.Trusted -> {
                    Log.i(TAG, "Payment module initialized on trusted device")
                }
            }

            // Connect billing client
            billingManager.connect()

            initialized = true
            Result.success(integrityStatus)
        } catch (e: Exception) {
            Log.e(TAG, "Payment module initialization failed", e)
            Result.failure(e)
        }
    }

    /**
     * Perform a wallet top-up with full integrity verification.
     */
    suspend fun topUpWallet(amount: Double, description: String = "Wallet top-up"): PaymentResult {
        ensureInitialized()
        return walletManager.processWalletTransaction(
            amount, TransactionType.WALLET_TOP_UP, description
        )
    }

    /**
     * Make a purchase from wallet balance with full integrity verification.
     */
    suspend fun purchaseFromWallet(
        amount: Double,
        description: String
    ): PaymentResult {
        ensureInitialized()
        return walletManager.processWalletTransaction(
            amount, TransactionType.PURCHASE, description
        )
    }

    /**
     * Withdraw from wallet with full integrity verification.
     */
    suspend fun withdrawFromWallet(
        amount: Double,
        description: String = "Wallet withdrawal"
    ): PaymentResult {
        ensureInitialized()
        return walletManager.processWalletTransaction(
            amount, TransactionType.WALLET_WITHDRAWAL, description
        )
    }

    /**
     * Get current device integrity status.
     */
    fun checkDeviceIntegrity(): DeviceIntegrityStatus {
        return integrityChecker.performFullIntegrityCheck()
    }

    /**
     * Verify transaction log has not been tampered with.
     */
    fun verifyTransactionLogIntegrity(): Boolean {
        return transactionLogger.verifyChainIntegrity()
    }

    /**
     * Clean up resources.
     */
    fun shutdown() {
        billingManager.disconnect()
        initialized = false
    }

    private fun ensureInitialized() {
        check(initialized) { "PaymentModule must be initialized before use. Call initialize() first." }
    }
}